CREATE OR REPLACE FUNCTION OFSERM.T2T_ACCT_LEVEL_GEN_PROV_STD_ACCT_HEAD_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FCT_STANDARD_ACCT_HEAD(N_CAP_COMP_GROUP_SKEY,N_STD_ACCT_HEAD_SKEY,N_STD_ACCT_HEAD_AMT,N_ENTITY,N_GAAP_SKEY,N_MIS_DATE_SKEY,N_RUN_SKEY)SELECT  /*+PARALLEL (4)*/ to_char(DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY),to_char(DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY),SUM(FCT_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_AMT),to_char(FCT_STANDARD_ACCT_HEAD.N_ENTITY),to_char(FCT_STANDARD_ACCT_HEAD.N_GAAP_SKEY),to_char(FCT_STANDARD_ACCT_HEAD.N_MIS_DATE_SKEY),to_char(FCT_STANDARD_ACCT_HEAD.N_RUN_SKEY) FROM ( select FSI_CAP_BANKING_EXPOSURES.N_ENTITY_SKEY N_ENTITY, FSI_CAP_BANKING_EXPOSURES.N_GAAP_SKEY , FSI_CAP_BANKING_EXPOSURES.N_MIS_DATE_SKEY , FSI_CAP_BANKING_EXPOSURES.N_RUN_SKEY , COALESCE(FSI_CAP_BANKING_EXPOSURES.N_GENERAL_PROVISION_AMT,0) N_STD_ACCT_HEAD_AMT from FSI_CAP_BANKING_EXPOSURES INNER JOIN DIM_DATES ON DIM_DATES.n_date_skey = FSI_CAP_BANKING_EXPOSURES.n_mis_date_skey AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_BANKING_EXPOSURES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_BANKING_EXPOSURES.N_CAP_RECORD_TYPE_SKEY AND FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870'     AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'CS' INNER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY = FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY AND FSI_RUN_PARAMETER.V_DATA_GRAN_GEN_PROV = 'OPTGRAN01' UNION ALL select FSI_CAP_INVESTMENT_EXPOSURES.N_ENTITY_SKEY N_ENTITY, FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY , FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY , FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY , COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_GENERAL_PROVISION_AMT,0) N_STD_ACCT_HEAD_AMT from FSI_CAP_INVESTMENT_EXPOSURES INNER JOIN DIM_DATES ON DIM_DATES.n_date_skey = FSI_CAP_INVESTMENT_EXPOSURES.n_mis_date_skey AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_RECORD_TYPE_SKEY AND FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_EXP' INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870'     AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'CS' INNER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY = FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY AND FSI_RUN_PARAMETER.V_DATA_GRAN_GEN_PROV = 'OPTGRAN01' UNION ALL select FSI_CAP_SFT_EXPOSURES.N_ENTITY_SKEY N_ENTITY, FSI_CAP_SFT_EXPOSURES.N_GAAP_SKEY , FSI_CAP_SFT_EXPOSURES.N_MIS_DATE_SKEY , FSI_CAP_SFT_EXPOSURES.N_RUN_SKEY , COALESCE(FSI_CAP_SFT_EXPOSURES.N_GENERAL_PROVISION_AMT,0) N_STD_ACCT_HEAD_AMT from FSI_CAP_SFT_EXPOSURES INNER JOIN DIM_DATES ON DIM_DATES.n_date_skey = FSI_CAP_SFT_EXPOSURES.n_mis_date_skey AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_SFT_EXPOSURES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_SFT_EXPOSURES.N_CAP_RECORD_TYPE_SKEY AND FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'SFT_NON_SEC_EXP' INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870'     AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'CS' INNER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY = FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY AND FSI_RUN_PARAMETER.V_DATA_GRAN_GEN_PROV = 'OPTGRAN01' UNION ALL select FSI_CAP_DERIVATIVES.N_ENTITY_SKEY N_ENTITY, FSI_CAP_DERIVATIVES.N_GAAP_SKEY , FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY , FSI_CAP_DERIVATIVES.N_RUN_SKEY , COALESCE(FSI_CAP_DERIVATIVES.N_GENERAL_PROVISION_AMT,0) N_STD_ACCT_HEAD_AMT from FSI_CAP_DERIVATIVES INNER JOIN DIM_DATES ON DIM_DATES.n_date_skey = FSI_CAP_DERIVATIVES.n_mis_date_skey AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_CAP_RECORD_TYPE_SKEY AND FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_EXP' INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870'     AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'CS' INNER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY = FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY AND FSI_RUN_PARAMETER.V_DATA_GRAN_GEN_PROV = 'OPTGRAN01') FCT_STANDARD_ACCT_HEAD INNER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IN ( 'CAP051') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_STANDARD_ACCT_HEAD.D_RECORD_START_DATE AND DIM_STANDARD_ACCT_HEAD.D_RECORD_END_DATE INNER JOIN DIM_CAPITAL_COMP_GROUP ON TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_CAPITAL_COMP_GROUP.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND COALESCE(DIM_CAPITAL_COMP_GROUP.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'OTH' WHERE 1=1 AND 1=1 GROUP BY FCT_STANDARD_ACCT_HEAD.n_mis_date_skey, FCT_STANDARD_ACCT_HEAD.N_RUN_SKEY, FCT_STANDARD_ACCT_HEAD.N_ENTITY, FCT_STANDARD_ACCT_HEAD.N_GAAP_SKEY, DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY, dim_capital_comp_group.n_cap_comp_group_skey LOG ERRORS INTO FCT_STANDARD_ACCT_HEAD$ ('1776770943143_49802381_20260331_1_JOB_6649379887737559') REJECT LIMIT UNLIMITED;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
